Description: Searches global news for specific supply chain disruptions (strikes, port delays). Use for verifying reported incidents with citable links.

JSON Schema:

JSON
{
  "type": "object",
  "properties": {
    "city": { "type": "string", "description": "The city name to search for." },
    "country": { "type": "string", "description": "The country name to search for." }
  },
  "required": ["city", "country"]
}

parameters.jsCode:
// Ensure inputs are treated as numbers
const geo = parseFloat($input.geographic) || 0;
const avail = parseFloat($input.availability) || 0;
const lt = parseFloat($input.lead_time) || 0;
const subst = parseFloat($input.substitutability) || 0;
const histAdj = parseFloat($input.historical_adjustment) || 0;

// Weighted formula
const weightedScore = (geo * 0.2) + (avail * 0.3) + (lt * 0.3) + (subst * 0.2);
const finalScore = Math.min(10, weightedScore + histAdj);

let riskStatus = "NOMINAL";
if (finalScore >= 7) riskStatus = "CRITICAL";
else if (finalScore >= 4) riskStatus = "ELEVATED";

// THIS IS THE CRITICAL CHANGE FOR AGENT TOOLS:
// Returning a single object inside the array so the Agent can "read" the keys
return [
  {
    risk_score: parseFloat(finalScore.toFixed(1)),
    status: riskStatus
  }
];

